<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        add_column </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:tickets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:importance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:string</span></span>
